import{_ as n,C as o,o as i,c as r,ag as s,E as t}from"./chunks/framework.DLWhSH9p.js";const b=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),l={name:"guide/index.md"};function p(d,e,c,h,u,g){const a=o("SchemeImage");return i(),r("div",null,[e[0]||(e[0]=s('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>CRAFT Studio is a YouTube content creation platform with AI-powered idea generation, script writing, video production, audio, competitive research, and multi-source resource discovery — backed by PostgreSQL, NATS workers, and specialized AI agents.</p><h2 id="what-you-can-do" tabindex="-1">What You Can Do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What You Can Do&quot;">​</a></h2><ul><li><strong>Generate Ideas</strong> — AI-powered brainstorming with channel personality, or save from YouTube research</li><li><strong>Write Scripts</strong> — AI write, revise, polish with fact-checking and humanization (Claude, Gemini, Ollama)</li><li><strong>Produce Videos</strong> — 7-stage pipeline orchestrated by AI agents, rendered with ffmpeg</li><li><strong>Research Competitors</strong> — YouTube search with outlier detection, channel deep dives, and earnings estimates</li><li><strong>Curate Content</strong> — AI-scored proposals, approval workflows, and episode pipeline tracking</li><li><strong>Produce Audio</strong> — 300+ TTS voices with screenplay-aware parsing, GPU speech synthesis, and voice cloning</li><li><strong>Find Resources</strong> — Search 14 royalty-free sources for video, image, audio, and reference material</li><li><strong>Collaborate</strong> — invite editors, video editors, and voice actors per channel; review notes pin to the timeline</li><li><strong>Go Mobile</strong> — Android companion app with full dashboard parity over your local network</li></ul>',4)),t(a,{name:"top-chrome",alt:"Top chrome — the Flow redesign layout"}),t(a,{name:"episodes-panel",alt:"Episodes kanban — every show is a card moving across the pipeline"}),t(a,{name:"channel-dive",alt:"Channel Deep Dive"}),e[1]||(e[1]=s(`<h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The Studio is organised around a <strong>top chrome</strong> — a single header bar — rather than a left sidebar. In it:</p><ul><li><strong>Logo · channel pill</strong> on the left</li><li><strong>Ad / promo slot</strong> between the channel pill and the search box. Free-tier users see a curated affiliate offer for creator tools (ElevenLabs, Descript, etc); active subscribers see a rotating marketplace spotlight; the slot collapses on narrow viewports.</li><li><strong>⌘K command palette</strong> slot in the middle-right</li><li><strong>Stage rail</strong> on the row below (<code>Discover → Proposals → Episodes → Publish</code>) — the workflow stages, with <strong>Marketplace · Settings · Feedback</strong> on the far right. Proposals only appears for premium users.</li><li><strong>Avatar menu</strong> top-right (API keys, password change, theme, sign out)</li></ul><p>Channel settings live inside the channel-pill dropdown. Jobs are inlined as a section under Proposals. Ideas no longer has its own panel — Episodes is the single backlog (Proposals → &quot;Create Episode&quot; and Discover → &quot;Inspire&quot; both land on the kanban). See <a href="/guide/command-palette.html">Top chrome &amp; ⌘K</a> for the full tour.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser ──&gt; Studio API ──&gt; Studio runtime</span></span>
<span class="line"><span>              |-- AI (Claude Agent SDK + Gemini + Ollama)</span></span>
<span class="line"><span>              |-- AI Agents (research, write, storyboard, assets...)</span></span>
<span class="line"><span>              |-- YouTube research (yt-dlp + Data API)</span></span>
<span class="line"><span>              |-- TTS (Edge TTS, ElevenLabs, OpenAI, OpenedAI Speech)</span></span>
<span class="line"><span>              |-- Background workers (idea, tts, discover, render...)</span></span>
<span class="line"><span>              |-- Role-based multi-tenant access</span></span>
<span class="line"><span>              |-- Feedback → GitHub Issues (AI grooming + worker)</span></span>
<span class="line"><span>              |-- Persistent storage + caching</span></span>
<span class="line"><span>              |-- ffmpeg composition render</span></span>
<span class="line"><span>              \\-- GPU Services (Ollama, MusicGen, OpenedAI Speech)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Mobile App ──&gt; Same Studio API (local network)</span></span></code></pre></div><h2 id="getting-into-the-studio" tabindex="-1">Getting into the Studio <a class="header-anchor" href="#getting-into-the-studio" aria-label="Permalink to &quot;Getting into the Studio&quot;">​</a></h2><p>Once you&#39;re signed in, the top chrome gives you everything:</p><ul><li><strong>Channel pill</strong> on the left — switch channels, or create your first one.</li><li><strong>Stage rail</strong> across the middle — Discover → Proposals → Episodes → Publish.</li><li><strong>⌘K</strong> — search and navigate everything without leaving the keyboard.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ollama runs locally and is available to every user — no API key required. Add a Gemini or Claude key (avatar menu → API keys) to unlock those providers.</p></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/guide/command-palette.html">Top chrome &amp; ⌘K</a> — the shortest tour of the new layout</li><li><a href="/guide/channels.html">Channels</a> — create your first channel</li><li><a href="/guide/episodes.html">Episodes</a> — your single backlog and pipeline</li><li><a href="/guide/proposals.html">Proposals</a> — AI brainstorms your next episode</li></ul>`,12))])}const v=n(l,[["render",p]]);export{b as __pageData,v as default};
